INSERT INTO itinerary_steps(tour_id,step_order,text_en,text_es)VALUES
(1,1,'Hotel pickup at the time you choose (we suggest 7-8 AM)','Recogida en su hotel a la hora que elija (sugerimos 7-8 AM)'),
(1,2,'Visit Tulum ruins. Hire a tour guide on-site or explore on your own.','Visite las ruinas de Tulum. Contrate un guia en el sitio o explore por su cuenta.'),
(1,3,'The driver can suggest traditional Mexican restaurants for lunch (not included).','El conductor puede sugerir restaurantes mexicanos tradicionales para el almuerzo (no incluido).'),
(1,4,'Return to your hotel at your convenience.','Regreso a su hotel a su conveniencia.');
INSERT INTO itinerary_steps(tour_id,step_order,text_en,text_es)VALUES
(2,1,'Hotel pickup at the time you choose (we suggest 7-8 AM)','Recogida en su hotel a la hora que elija (sugerimos 7-8 AM)'),
(2,2,'Tulum ruins. Hire a tour guide or just explore on your own.','Ruinas de Tulum. Contrate un guia o simplemente explore por su cuenta.'),
(2,3,'The driver can suggest traditional Mexican restaurants for lunch.','El conductor puede sugerir restaurantes mexicanos tradicionales para el almuerzo.'),
(2,4,'Akumal Bay for snorkeling with the sea turtles.','Bahia de Akumal para snorkel con las tortugas marinas.');
INSERT INTO itinerary_steps(tour_id,step_order,text_en,text_es)VALUES
(3,1,'Choose your tour time: 9:30 AM or 1:30 PM departure','Elige tu horario: salida a las 9:30 AM o 1:30 PM'),
(3,2,'Hotel pickup and round-trip transportation','Recogida en hotel y transporte ida y vuelta'),
(3,3,'5 zip lines and 3 balance bridges through the jungle canopy','5 tirolesas y 3 puentes de equilibrio sobre la selva'),
(3,4,'50 minutes of ATV riding through jungle trails','50 minutos de paseo en ATV por senderos en la selva'),
(3,5,'50 minutes of swimming at an open cenote with zip lines and jump platforms','50 minutos de nado en cenote abierto con tirolesas y plataformas de salto');
INSERT INTO itinerary_steps(tour_id,step_order,text_en,text_es)VALUES
(4,1,'Hotel pickup in Cancun or Puerto Juarez','Recogida en hotel en Cancun o Puerto Juarez'),
(4,2,'Transfer to group bus with guide','Traslado a autobus grupal con guia'),
(4,3,'Visit Chichen Itza pyramids','Visita a las piramides de Chichen Itza'),
(4,4,'Lunch at local restaurant','Almuerzo en restaurante local'),
(4,5,'Swimming in sacred cenote','Nado en cenote sagrado'),
(4,6,'Return to hotel','Regreso al hotel');
INSERT INTO itinerary_steps(tour_id,step_order,text_en,text_es)VALUES
(5,1,'Check in at Cancun Bay Resort Marina KM 3.5 (next to Temptation Resort) by 9:30 AM.','Registro en Cancun Bay Resort Marina KM 3.5 (junto a Temptation Resort) antes de las 9:30 AM.'),
(5,2,'Snorkeling on the reef for 45 minutes.','Snorkel en el arrecife durante 45 minutos.'),
(5,3,'1 hour free time on Isla Mujeres for shopping and exploring.','1 hora de tiempo libre en Isla Mujeres para compras y exploracion.'),
(5,4,'Buffet lunch with pasta, fish, chicken, beef, salads, rice, beans, and dessert.','Almuerzo buffet con pasta, pescado, pollo, carne, ensaladas, arroz, frijoles y postre.'),
(5,5,'Enjoy Parayo beach club: relax in hammocks and lounge chairs, swim in the ocean, or interact with the shark area.','Disfruta el club de playa Parayo: relajate en hamacas y camastros, nada en el mar o interactua con el area de tiburon.'),
(5,6,'On the way back to Cancun, the boat anchors so everyone can try the spinnaker (weather permitting), with open bar on board.','En el regreso a Cancun, la embarcacion ancla para probar el spinnaker (si el clima lo permite), con barra libre a bordo.'),
(5,7,'Arrive back at the marina between 5:00 PM and 5:30 PM.','Regreso a la marina entre 5:00 PM y 5:30 PM.');
INSERT INTO itinerary_steps(tour_id,step_order,text_en,text_es)VALUES
(6,1,'Hotel pickup at your preferred time (suggested 7-8 AM)','Recogida en hotel a la hora que prefiera (sugerido 7-8 AM)'),
(6,2,'Private drive from Cancun to Coba (about 2 hours)','Traslado privado de Cancun a Coba (aprox. 2 horas)'),
(6,3,'Explore Coba ruins by bike or on your own, including pyramid climbing','Explora las ruinas de Coba en bicicleta o por tu cuenta, incluyendo subida a piramides'),
(6,4,'Optional: hire an official guide at the entrance for a 90 minute guided visit','Opcional: contratar un guia oficial en la entrada para un recorrido guiado de 90 minutos'),
(6,5,'Driver can suggest traditional Mexican restaurants for lunch','El chofer puede sugerir restaurantes mexicanos tradicionales para almuerzo'),
(6,6,'Optional add-ons: cenotes Tankach Ha and Multum Ha, or Mayan family home visit','Opcionales: cenotes Tankach Ha y Multum Ha, o visita a casa de familia maya'),
(6,7,'Return transfer after your visit (all ruins close at 5:00 PM)','Traslado de regreso despues de su visita (todas las ruinas cierran a las 5:00 PM)');
INSERT INTO itinerary_steps(tour_id,step_order,text_en,text_es)VALUES
(7,1,'9:00 AM - 10:30 AM: Continental breakfast during boat ride to Ixlache Reef','9:00 AM - 10:30 AM: Desayuno continental durante el trayecto en lancha al Arrecife Ixlache'),
(7,2,'10:30 AM - 11:15 AM: Snorkeling on the reef (equipment and reef tax extra), or stay on the boat','10:30 AM - 11:15 AM: Snorkel en el arrecife (equipo e impuesto de arrecife se pagan aparte), o permanecer en la embarcacion'),
(7,3,'11:15 AM - 3:30 PM: Isla Contoy guided tour and free time to explore','11:15 AM - 3:30 PM: Tour guiado en Isla Contoy y tiempo libre para explorar'),
(7,4,'2:10 PM - 3:30 PM: Buffet lunch on the island','2:10 PM - 3:30 PM: Almuerzo buffet en la isla'),
(7,5,'3:45 PM - 5:00 PM: Return to Cancun','3:45 PM - 5:00 PM: Regreso a Cancun');
INSERT INTO itinerary_steps(tour_id,step_order,text_en,text_es)VALUES
(8,1,'7:30 AM departure from Puerto Juarez dock with continental breakfast and safety briefing','Salida 7:30 AM desde el muelle de Puerto Juarez con desayuno continental y briefing de seguridad'),
(8,2,'Navigate to the whale shark area and remain there for almost 2 hours','Navegacion hacia el area de tiburon ballena y permanencia por casi 2 horas'),
(8,3,'Snorkel in pairs for 5-10 minutes per turn, with approximately 2-4 turns per person','Snorkel en parejas por turnos de 5-10 minutos, con aproximadamente 2-4 turnos por persona'),
(8,4,'Possible sightings include manta rays, dolphins, and turtles','Posibles avistamientos incluyen mantarrayas, delfines y tortugas'),
(8,5,'Visit Playa Norte and enjoy refreshments, fresh ceviche, and sandwiches','Visita a Playa Norte y disfrute de bebidas, ceviche fresco y sandwiches'),
(8,6,'Return around 2:00 PM','Regreso alrededor de las 2:00 PM');
INSERT INTO itinerary_steps(tour_id,step_order,text_en,text_es)VALUES
(9,1,'Hotel pickup and private transfer to Ek Balam','Recogida en hotel y traslado privado a Ek Balam'),
(9,2,'Climb Ek Balam ruins and explore the Mayan carvings','Sube las ruinas de Ek Balam y explora los grabados mayas'),
(9,3,'Bike to Xcanche cenote','Recorrido en bicicleta hacia el cenote Xcanche'),
(9,4,'Enjoy unlimited cenote activities: rappel, rope swing, zipline, and swimming','Disfruta actividades ilimitadas en el cenote: rappel, columpio de cuerda, tirolesa y nado'),
(9,5,'Optional lunch stop at the cenote or in Valladolid','Parada opcional para almuerzo en el cenote o en Valladolid'),
(9,6,'Visit Valladolid cathedral','Visita a la catedral de Valladolid'),
(9,7,'Return transfer to your hotel','Traslado de regreso a su hotel');
INSERT INTO itinerary_steps(tour_id,step_order,text_en,text_es)VALUES
(10,1,'Hotel pickup at your preferred time','Recogida en hotel a la hora de su preferencia'),
(10,2,'Visit your selected shopping stops in Cancun (Market 28, Market 23, Walmart, Plaza La Isla, Plaza Las Americas, Tulum Avenue, and more)','Visita a sus paradas de compras seleccionadas en Cancun (Mercado 28, Mercado 23, Walmart, Plaza La Isla, Plaza Las Americas, Avenida Tulum y mas)'),
(10,3,'Driver secures your belongings while you shop and can help with translation or bargaining','El chofer resguarda sus pertenencias mientras compra y puede ayudar con traduccion o negociacion'),
(10,4,'Optional extra time can be added at hourly rate','Tiempo extra opcional disponible con tarifa por hora'),
(10,5,'Return transfer to your hotel','Traslado de regreso a su hotel');
INSERT INTO itinerary_steps(tour_id,step_order,text_en,text_es)VALUES
(11,1,'Suggested departure from Cancun between 7:00 AM and 8:00 AM','Salida sugerida desde Cancun entre 7:00 AM y 8:00 AM'),
(11,2,'Drive about 2.5 hours to Chichen Itza','Traslado de aproximadamente 2.5 horas a Chichen Itza'),
(11,3,'Spend 2-3 hours exploring the ruins','Tiempo de 2-3 horas para explorar las ruinas'),
(11,4,'Continue to Ik Kil cenote for swimming','Continuacion al cenote Ik Kil para nadar'),
(11,5,'Enjoy gourmet buffet lunch','Disfrute de almuerzo buffet gourmet'),
(11,6,'Optional stop in Valladolid on the return to Cancun','Parada opcional en Valladolid durante el regreso a Cancun'),
(11,7,'Return transfer to your hotel','Traslado de regreso a su hotel');
INSERT INTO addons(tour_id,slug,title_en,title_es,desc_en,desc_es,price_per_person)VALUES
(1,'reef-snorkel','Reef Snorkeling in Puerto Morelos','Snorkel en Arrecife en Puerto Morelos','Our favorite spot to snorkel on the coral reef. Includes gear and guide.','Nuestro lugar favorito para hacer snorkel en el arrecife de coral. Incluye equipo y guia.',30),
(1,'turtle-snorkel','Akumal Sea Turtle Snorkel','Snorkel con Tortugas Marinas en Akumal','Snorkel with sea turtles in their natural environment. Easy and safe snorkeling right from the beach. Includes snorkel gear.','Haga snorkel con tortugas marinas en su ambiente natural. Snorkel facil y seguro desde la playa. Incluye equipo de snorkel.',30);
INSERT INTO addons(tour_id,slug,title_en,title_es,desc_en,desc_es,price_per_person)VALUES
(2,'reef-snorkel-pm','Reef Snorkeling in Puerto Morelos','Snorkel en Arrecife en Puerto Morelos','Our favorite spot to snorkel on the coral reef. Includes gear and guide.','Nuestro lugar favorito para hacer snorkel en el arrecife de coral. Incluye equipo y guia.',30);
INSERT INTO addons(tour_id,slug,title_en,title_es,desc_en,desc_es,price_per_person)VALUES
(5,'riviera_maya_roundtrip_transport','Round-Trip Transportation from Riviera Maya','Transporte Redondo desde Riviera Maya','Optional add-on for round-trip transportation between Riviera Maya and the marina.','Adicional opcional de transporte redondo entre Riviera Maya y la marina.',15);
INSERT INTO addons(tour_id,slug,title_en,title_es,desc_en,desc_es,price_per_person)VALUES
(11,'ek_balam_ruins_add_on','Add-On: Ek Balam Ruins','Adicional: Ruinas de Ek Balam','Climb the ruins and see distinct carvings up close. Available for Cancun, Puerto Morelos and Playa Paraiso hotels only.','Sube las ruinas y observa de cerca sus grabados distintivos. Disponible solo para hoteles en Cancun, Puerto Morelos y Playa Paraiso.',10),
(11,'coba_ruins_add_on','Add-On: Coba Ruins','Adicional: Ruinas de Coba','Climb Coba ruins on an off-the-beaten-path site. Available for Playa del Carmen, Puerto Aventuras, Akumal and Tulum hotels only.','Sube las ruinas de Coba en un sitio fuera de la ruta tradicional. Disponible solo para hoteles en Playa del Carmen, Puerto Aventuras, Akumal y Tulum.',10);
